  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// En V1 usamos SQLite local para arrancar rápido.\n// Luego puede migrar 1:1 a Postgres (Supabase) sin cambiar el modelo.\n\nmodel ServiceCategory {\n  id        Int      @id @default(autoincrement())\n  code      String   @unique // UÑAS | DEPILACION | CEJAS_Y_PESTANAS\n  name      String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  services Service[]\n}\n\nmodel Neighborhood {\n  id        Int      @id @default(autoincrement())\n  locality  String\n  name      String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  addresses Address[]\n\n  @@unique([locality, name])\n  @@index([locality])\n}\n\nmodel Role {\n  id        Int      @id @default(autoincrement())\n  code      RoleCode @unique\n  name      String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  users UserRole[]\n}\n\nmodel User {\n  id           Int        @id @default(autoincrement())\n  email        String     @unique\n  passwordHash String\n  fullName     String\n  phoneE164    String?    @unique\n  status       UserStatus @default(ACTIVE)\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  roles     UserRole[]\n  auditLogs AuditLog[]\n}\n\nmodel UserRole {\n  userId Int\n  roleId Int\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  role Role @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@id([userId, roleId])\n  @@index([roleId])\n}\n\nmodel AuditLog {\n  id          Int      @id @default(autoincrement())\n  actorUserId Int?\n  action      String\n  entity      String\n  entityId    Int?\n  metadata    Json?\n  createdAt   DateTime @default(now())\n\n  actor User? @relation(fields: [actorUserId], references: [id], onDelete: SetNull)\n\n  @@index([createdAt])\n  @@index([entity, entityId])\n}\n\nmodel Customer {\n  id        Int      @id @default(autoincrement())\n  fullName  String\n  phoneE164 String?  @unique\n  email     String?  @unique\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  addresses    Address[]\n  appointments Appointment[]\n}\n\nmodel Address {\n  id             Int      @id @default(autoincrement())\n  customerId     Int?\n  neighborhoodId Int?\n  label          String?\n  line1          String\n  mapsUrl        String?\n  latitude       Float?\n  longitude      Float?\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  customer     Customer?     @relation(fields: [customerId], references: [id], onDelete: SetNull)\n  neighborhood Neighborhood? @relation(fields: [neighborhoodId], references: [id], onDelete: SetNull)\n  appointments Appointment[]\n\n  @@index([neighborhoodId])\n}\n\nmodel Service {\n  id          Int      @id @default(autoincrement())\n  categoryId  Int\n  name        String\n  // duración estimada en minutos (rango) para agendamiento\n  durationMin Int\n  durationMax Int\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  category ServiceCategory             @relation(fields: [categoryId], references: [id], onDelete: Restrict)\n  prices   ServicePrice[]\n  planned  AppointmentPlannedService[]\n  actual   AppointmentActualService[]\n\n  @@unique([categoryId, name])\n}\n\n// Normalización de precios: el precio puede cambiar sin reescribir el catálogo.\nmodel ServicePrice {\n  id            Int       @id @default(autoincrement())\n  serviceId     Int\n  amountCOP     Int\n  currency      String    @default(\"COP\")\n  effectiveFrom DateTime  @default(now())\n  effectiveTo   DateTime?\n  createdAt     DateTime  @default(now())\n\n  service Service @relation(fields: [serviceId], references: [id], onDelete: Cascade)\n\n  @@index([serviceId, effectiveFrom])\n}\n\nmodel FormSubmission {\n  id        Int      @id @default(autoincrement())\n  sourceKey String   @unique\n  payload   Json\n  createdAt DateTime @default(now())\n\n  appointment Appointment?\n}\n\nmodel Appointment {\n  id                Int       @id @default(autoincrement())\n  customerId        Int\n  addressId         Int?\n  startAt           DateTime?\n  endAt             DateTime?\n  // Preferencias del cliente desde el Form (antes de confirmación de ruta)\n  requestedStartAt  DateTime?\n  requestedTimeText String?\n  requestedFlexible Boolean?\n  // \"lead\" puede ser quien agenda, aunque el servicio sea para otra(s) persona(s)\n  leadName          String?\n  leadPhoneE164     String?\n\n  status AppointmentStatus @default(PENDING)\n  notes  String?\n\n  // Control de origen (para trazabilidad con Google Forms/Sheets)\n  source           String @default(\"google_form\")\n  formSubmissionId Int?   @unique\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  customer       Customer        @relation(fields: [customerId], references: [id], onDelete: Restrict)\n  address        Address?        @relation(fields: [addressId], references: [id], onDelete: SetNull)\n  formSubmission FormSubmission? @relation(fields: [formSubmissionId], references: [id], onDelete: SetNull)\n\n  participants    AppointmentParticipant[]\n  plannedServices AppointmentPlannedService[]\n  actualServices  AppointmentActualService[]\n  payments        Payment[]\n\n  @@index([status, startAt])\n}\n\nmodel AppointmentParticipant {\n  id            Int      @id @default(autoincrement())\n  appointmentId Int\n  fullName      String?\n  // Ej: \"para mí\", \"para alguien más\", \"grupo\"\n  roleLabel     String?\n  notes         String?\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  appointment Appointment @relation(fields: [appointmentId], references: [id], onDelete: Cascade)\n}\n\nmodel AppointmentPlannedService {\n  id            Int      @id @default(autoincrement())\n  appointmentId Int\n  serviceId     Int\n  quantity      Int      @default(1)\n  priceCOP      Int?\n  notes         String?\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  appointment Appointment @relation(fields: [appointmentId], references: [id], onDelete: Cascade)\n  service     Service     @relation(fields: [serviceId], references: [id], onDelete: Restrict)\n\n  @@unique([appointmentId, serviceId])\n}\n\nmodel AppointmentActualService {\n  id            Int                 @id @default(autoincrement())\n  appointmentId Int\n  serviceId     Int\n  quantity      Int                 @default(1)\n  priceCOP      Int?\n  // Si fue agregado en domicilio o cambió respecto a lo planeado\n  origin        ActualServiceOrigin @default(ON_SITE_ADDED)\n  notes         String?\n  createdAt     DateTime            @default(now())\n  updatedAt     DateTime            @updatedAt\n\n  appointment Appointment @relation(fields: [appointmentId], references: [id], onDelete: Cascade)\n  service     Service     @relation(fields: [serviceId], references: [id], onDelete: Restrict)\n\n  @@index([appointmentId])\n}\n\nmodel Payment {\n  id            Int           @id @default(autoincrement())\n  appointmentId Int\n  amountCOP     Int\n  method        PaymentMethod\n  paidAt        DateTime      @default(now())\n  reference     String?\n  notes         String?\n\n  appointment Appointment @relation(fields: [appointmentId], references: [id], onDelete: Cascade)\n\n  @@index([paidAt])\n}\n\nenum AppointmentStatus {\n  PENDING\n  CONFIRMED\n  IN_ROUTE\n  IN_SERVICE\n  COMPLETED\n  CANCELLED\n  NO_SHOW\n}\n\nenum PaymentMethod {\n  CASH\n  TRANSFER\n  NEQUI\n  DAVIPLATA\n  CARD\n  OTHER\n}\n\nenum ActualServiceOrigin {\n  RESERVED\n  ON_SITE_CHANGED\n  ON_SITE_ADDED\n}\n\nenum RoleCode {\n  OWNER\n  ADMIN\n  STAFF\n  VIEWER\n}\n\nenum UserStatus {\n  ACTIVE\n  DISABLED\n}\n",
  "inlineSchemaHash": "b6c9121667d3ef5992302d0f477ca9e4c83ee49b40a42e72803a26e142133a84",
